import './App.css';

function Navibar(){
    const ModalClickMainDiary = () => {
        navigate('/');
    }
    return(
            <nav>
                    <div className='logo'>
                        HashTAG
                    </div>
                    <div>
                        <ul className='login_signup'>
                            <li>
                                <a href='#'>Login</a>
                            </li>
                            <li>
                                <a href='#'>Sign Up</a>
                            </li>
                        </ul>
                    </div>
                </nav>
    )
}

export default Navibar;
